#!/usr/bin/env python3
# (C) Datadog, Inc. 2026-present
# All rights reserved
# Licensed under a 3-clause BSD style license (see LICENSE)
"""Reproducible census of ``requests``-specific references across the tree.

This is the executable, committed backing for the httpx migration sweeps. It
scans every git-tracked ``*.py`` file, classifies the ``requests`` references
that downstream slices must retire, and tags each hit with its owning
integration, whether the file ships with the Agent, and whether it is test code.

It also locks a static invariant: the base wrapper's translation seam catches
``requests_exceptions.RequestException`` (the base class of every requests
error), which guarantees the base wrapper's translation is *total* -- every
requests error maps to an agnostic ``http_exceptions`` type. If that invariant
ever regresses, this script exits non-zero.

Running it regenerates ``.r2/httpx_census.json`` deterministically.
"""

from __future__ import annotations

import ast
import io
import json
import re
import subprocess
import sys
import tokenize
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

# Directories whose Python is developer tooling or the base machinery itself,
# not an integration that the migration sweep has to touch. Hits here are
# recorded but flagged as not-shipped so the sweeps can exclude them.
EXEMPT_PREFIXES = (
    "datadog_checks_base/",
    "datadog_checks_dev/",
    "ddev/",
    ".ddev/",
)

# The base wrapper is the thing performing the translation; it is excluded from
# the census entirely rather than merely flagged.
BASE_WRAPPER = "datadog_checks_base/datadog_checks/base/utils/http.py"

CENSUS_JSON = ROOT / ".r2" / "httpx_census.json"

# Each category is a (name, compiled regex) pair applied to comment-free code.
# A single line may match several categories; every match is recorded so the
# per-category file lists stay honest.
CATEGORIES: list[tuple[str, re.Pattern[str]]] = [
    ("except_requests_exceptions", re.compile(r"\bexcept\b[^:]*\brequests\.exceptions\b")),
    ("import_requests", re.compile(r"^\s*(?:from|import)\s+requests\b")),
    ("requests_attr", re.compile(r"\brequests\.\w+")),
    ("self_http_session", re.compile(r"\bself\.http\._?session\b")),
    ("authbase_subclass", re.compile(r"\bclass\s+\w+\s*\([^)]*\bAuthBase\b")),
    ("requests_response_construction", re.compile(r"\brequests\.Response\s*\(")),
    ("requests_session_patch", re.compile(r"\brequests\.Session\b")),
]


def git_tracked_python_files() -> list[str]:
    out = subprocess.run(
        ["git", "-C", str(ROOT), "ls-files", "*.py"],
        capture_output=True,
        text=True,
        check=True,
    )
    return sorted(line for line in out.stdout.splitlines() if line)


def strip_comments(text: str) -> list[str]:
    """Return the file's lines with comment text removed.

    Uses ``tokenize`` so ``#`` inside strings is not mistaken for a comment.
    Falls back to a line-prefix heuristic on files that fail to tokenize
    (for example lingering Python 2 syntax).
    """
    lines = text.splitlines()
    cut: dict[int, int] = {}
    try:
        for tok in tokenize.generate_tokens(io.StringIO(text).readline):
            if tok.type == tokenize.COMMENT:
                row, col = tok.start
                if row not in cut or col < cut[row]:
                    cut[row] = col
    except (tokenize.TokenError, IndentationError, SyntaxError):
        return ["" if line.lstrip().startswith("#") else line for line in lines]
    return [line[cut[i]] if False else (line[: cut[i]] if i in cut else line) for i, line in enumerate(lines, 1)]


def integration_of(path: str) -> str:
    head, _, tail = path.partition("/")
    return head if tail else ""


def is_test_file(path: str) -> bool:
    parts = path.split("/")
    base = parts[-1]
    return "tests" in parts or base.startswith("test_") or base == "conftest.py"


def is_shipped(path: str) -> bool:
    return not path.startswith(EXEMPT_PREFIXES)


def scan_file(path: str) -> list[dict]:
    full = ROOT / path
    try:
        text = full.read_text(encoding="utf-8")
    except (UnicodeDecodeError, OSError):
        return []
    hits: list[dict] = []
    for lineno, code in enumerate(strip_comments(text), 1):
        if "requests" not in code and "AuthBase" not in code:
            continue
        for name, pattern in CATEGORIES:
            if pattern.search(code):
                hits.append({"line": lineno, "category": name, "text": code.strip()})
    return hits


def wrapper_catches_request_exception() -> bool:
    """Static check that the base wrapper's translation seam is total.

    Confirms an ``except requests_exceptions.RequestException`` handler exists in
    the base wrapper and that ``_translate_requests_exception`` has a
    ``RequestException`` fallback branch. Together these guarantee every requests
    error is caught and mapped to an agnostic type.
    """
    source = (ROOT / BASE_WRAPPER).read_text(encoding="utf-8")
    tree = ast.parse(source)

    def is_request_exception(node: ast.expr | None) -> bool:
        return (
            isinstance(node, ast.Attribute)
            and node.attr == "RequestException"
            and isinstance(node.value, ast.Name)
            and node.value.id == "requests_exceptions"
        )

    catches = any(
        isinstance(node, ast.ExceptHandler) and is_request_exception(node.type) for node in ast.walk(tree)
    )
    fallback = any(
        isinstance(node, ast.Call)
        and isinstance(node.func, ast.Name)
        and node.func.id == "isinstance"
        and len(node.args) == 2
        and is_request_exception(node.args[1])
        for node in ast.walk(tree)
    )
    return catches and fallback


def reconcile(files: dict[str, dict]) -> list[str]:
    """Sanity-check the RFC census corrections against the live scan.

    Returns a list of failure messages; empty means every documented correction
    still holds.
    """
    failures: list[str] = []

    authbase_integrations = {
        rec["integration"]
        for rec in files.values()
        if rec["shipped"] and any(h["category"] == "authbase_subclass" for h in rec["hits"])
    }
    if authbase_integrations != {"voltdb"}:
        failures.append(
            f"expected voltdb to be the only shipped AuthBase subclass, found {sorted(authbase_integrations)}"
        )

    nifi = files.get("nifi/datadog_checks/nifi/api.py")
    if not nifi or not any(
        h["category"] == "import_requests" and "HTTPError" in h["text"] for h in nifi["hits"]
    ):
        failures.append("expected nifi/api.py to import HTTPError directly from requests")

    if "cloud_foundry_api" not in {rec["integration"] for rec in files.values()}:
        failures.append("expected cloud_foundry_api to appear in the census")

    return failures


def main() -> int:
    files: dict[str, dict] = {}
    for path in git_tracked_python_files():
        if path == BASE_WRAPPER:
            continue
        hits = scan_file(path)
        if not hits:
            continue
        files[path] = {
            "shipped": is_shipped(path),
            "test": is_test_file(path),
            "integration": integration_of(path),
            "hits": hits,
        }

    hits_by_category: dict[str, int] = {name: 0 for name, _ in CATEGORIES}
    for rec in files.values():
        for hit in rec["hits"]:
            hits_by_category[hit["category"]] += 1

    ref_files_total = len(files)
    ref_files_shipped = sum(1 for rec in files.values() if rec["shipped"])
    shipped_integrations = sorted(
        {rec["integration"] for rec in files.values() if rec["shipped"] and rec["integration"]}
    )

    catches = wrapper_catches_request_exception()

    snapshot = {
        "generated_by": ".r2/httpx_census.py",
        "base_wrapper": BASE_WRAPPER,
        "exempt_prefixes": list(EXEMPT_PREFIXES),
        "totals": {
            "ref_files_total": ref_files_total,
            "ref_files_shipped": ref_files_shipped,
            "shipped_integrations_touched": len(shipped_integrations),
            "wrapper_catches_request_exception": catches,
            "hits_by_category": hits_by_category,
        },
        "shipped_integrations": shipped_integrations,
        "files": dict(sorted(files.items())),
    }
    CENSUS_JSON.write_text(json.dumps(snapshot, indent=2, sort_keys=False) + "\n", encoding="utf-8")

    print(f"requests-reference files (total):   {ref_files_total}")
    print(f"requests-reference files (shipped): {ref_files_shipped}")
    print(f"shipped integrations touched:       {len(shipped_integrations)}")
    print("hits by category:")
    for name, _ in CATEGORIES:
        print(f"  {name}: {hits_by_category[name]}")
    print(f"snapshot written to {CENSUS_JSON.relative_to(ROOT)}")

    failures = reconcile(files)
    for message in failures:
        print(f"RECONCILE FAIL: {message}", file=sys.stderr)

    if catches:
        print("translation totality: base wrapper catches requests_exceptions.RequestException (OK)")
    else:
        print(
            "translation totality GAP: base wrapper does NOT catch "
            "requests_exceptions.RequestException",
            file=sys.stderr,
        )

    if not catches or failures:
        return 1
    return 0


if __name__ == "__main__":
    sys.exit(main())

